1	const PROCESSING_FEE = 5;
2	const BLOCK_PRICE = 60;
3	const BLOCK_SIZE = 3;
4	
5	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	type Item = { type: string; cursed?: boolean; enchantment?: number };
17	type Step = { items: Item[] };
18	type Customer = { yearsWithMHPCO: number; isFirstInsurance?: boolean };
19	type Scenario = { customer: Customer; steps: Step[] };
20	
21	const basePremiumFor = (type: string): number =>
22	  BASE_PREMIUM_BY_ITEM_TYPE[type] ?? 0;
23	
24	const isBlockOfAlikeComponents = (type: string, count: number): boolean =>
25	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
26	
27	const priceForGroup = (type: string, count: number): number =>
28	  isBlockOfAlikeComponents(type, count)
29	    ? BLOCK_PRICE
30	    : count * basePremiumFor(type);
31	
32	const countByType = (items: Item[]): Map<string, number> => {
33	  const counts = new Map<string, number>();
34	  for (const item of items) {
35	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
36	  }
37	  return counts;
38	};
39	
40	const CURSE_SURCHARGE_RATE = 0.5;
41	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
42	const HIGH_ENCHANTMENT_THRESHOLD = 5;
43	
44	const isHighlyEnchanted = (item: Item): boolean =>
45	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
46	
47	const surchargeRate = (item: Item): number =>
48	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
49	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
50	
51	const itemSurcharge = (item: Item): number =>
52	  basePremiumFor(item.type) * surchargeRate(item);
53	
54	const sumGroupedPrices = (items: Item[]): number => {
55	  let total = 0;
56	  for (const [type, count] of countByType(items)) {
57	    total += priceForGroup(type, count);
58	  }
59	  return total;
60	};
61	
62	const sumItemSurcharges = (items: Item[]): number => {
63	  let total = 0;
64	  for (const item of items) {
65	    total += itemSurcharge(item);
66	  }
67	  return total;
68	};
69	
70	const LOYALTY_DISCOUNT_RATE = 0.2;
71	const LOYALTY_THRESHOLD = 2;
72	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
73	
74	const isLongStandingCustomer = (customer: Customer): boolean =>
75	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD;
76	
77	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
78	  isLongStandingCustomer(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
79	
80	const firstInsuranceSurcharge = (policyBase: number, customer: Customer): number =>
81	  customer.isFirstInsurance ? policyBase * FIRST_INSURANCE_SURCHARGE_RATE : 0;
82	
83	const quotePremiumFor = (step: Step, customer: Customer): number => {
84	  const policyBase = sumGroupedPrices(step.items);
85	  const surcharges = sumItemSurcharges(step.items);
86	  return policyBase
87	    - loyaltyDiscount(policyBase, customer)
88	    + firstInsuranceSurcharge(policyBase, customer)
89	    + surcharges
90	    + PROCESSING_FEE;
91	};
92	
93	export const processScenario = (input: unknown): unknown => {
94	  const { customer, steps } = input as Scenario;
95	  return {
96	    results: steps.map((step) => ({ premium: quotePremiumFor(step, customer) })),
97	  };
98	};
